import { useState, createContext } from 'react'
import axios from 'axios'


const BookContext = createContext()

const BookProvider = ({children}) => {

    const [search, setSearch] = useState({
        query: ''
    })

    const [loading, setLoading] = useState(false)
    const [bookData, setBookData] = useState([])
    

    const getBookList = async datos => {
       
        setLoading(true)

        try {
            const url = "https://www.googleapis.com/books/v1/volumes?q=" + search.query + "&key=" + process.env.REACT_APP_GOOGLE_BOOKS_API_KEY + "&maxResults=40&printType=books&projection=lite";
            const { data: res } = await axios(url);
    
           
            if (res && res.items) {
                setBookData(res.items);
            } else {
                
                setBookData([]);
            }
        }
        catch{
            console.log()
        }
        finally{
            setLoading(false)
        }       
    }

    const clearBookList = () => {
        setBookData([]);
    };
    

    const [userBooks, setUserBooks] = useState([])

    const [userSearched, setUserSearched] = useState([])



    return (
        <BookContext.Provider value={{ getBookList, clearBookList, bookData, search, setSearch, loading, setLoading, userBooks, setUserBooks, userSearched, setUserSearched }}>
            {children}
        </BookContext.Provider>
    )
}

export { BookProvider }

export default BookContext
